1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUE: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
31	type Customer = { yearsWithMHPCO: number };
32	type Damage = { itemType: string; amount: number };
33	type Incident = { cause: string; damages: Damage[] };
34	type QuoteStep = { op: "quote"; items: Item[] };
35	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
36	type Step = QuoteStep | ClaimStep;
37	type Scenario = { customer: Customer; steps: Step[] };
38	type QuoteResult = { premium: number };
39	type ClaimResult = { payout: number; remainingCap: number };
40	type StepResult = QuoteResult | ClaimResult;
41	
42	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_BASE_PREMIUM = 60;
47	
48	const sumBasePremiums = (items: Item[]): number =>
49	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
50	
51	const componentGroupSubtotalOf = (group: Item[]): number =>
52	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
53	
54	const groupByType = (items: Item[]): Item[][] => {
55	  const groups = new Map<string, Item[]>();
56	  for (const item of items) {
57	    const group = groups.get(item.type);
58	    if (group) {
59	      group.push(item);
60	    } else {
61	      groups.set(item.type, [item]);
62	    }
63	  }
64	  return [...groups.values()];
65	};
66	
67	const componentSubtotalOf = (components: Item[]): number =>
68	  groupByType(components).reduce(
69	    (sum, group) => sum + componentGroupSubtotalOf(group),
70	    0,
71	  );
72	
73	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
74	
75	const policyBaseOf = (items: Item[]): number => {
76	  const components = items.filter(isComponent);
77	  const standaloneItems = items.filter((item) => !isComponent(item));
78	  return sumBasePremiums(standaloneItems) + componentSubtotalOf(components);
79	};
80	
81	const firstInsuranceSurchargeOf = (policyBase: number): number =>
82	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
83	
84	const cursedSurchargeOf = (item: Item): number =>
85	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
86	
87	const highEnchantmentSurchargeOf = (item: Item): number =>
88	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
89	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
90	    : 0;
91	
92	const itemSurchargeOf = (item: Item): number =>
93	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
94	
95	const itemSurchargesOf = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + itemSurchargeOf(item), 0);
97	
98	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
99	
100	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
101	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
102	
103	const followUpDiscountOf = (policyBase: number, isFollowUp: boolean): number =>
104	  isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
105	
106	const policySurchargesOf = (policyBase: number): number =>
107	  firstInsuranceSurchargeOf(policyBase);
108	
109	const policyDiscountsOf = (
110	  policyBase: number,
111	  customer: Customer,
112	  isFollowUp: boolean,
113	): number =>
114	  loyaltyDiscountOf(policyBase, customer) + followUpDiscountOf(policyBase, isFollowUp);
115	
116	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
117	  const policyBase = policyBaseOf(items);
118	  const surcharges = itemSurchargesOf(items) + policySurchargesOf(policyBase);
119	  const discounts = policyDiscountsOf(policyBase, customer, isFollowUp);
120	  const rawPremium = policyBase + surcharges - discounts + PROCESSING_FEE;
121	  return roundUpInMHPCOFavor(rawPremium);
122	};
123	
124	const isFollowUpContract = (stepIndex: number): boolean => stepIndex > 0;
125	
126	const insuranceSumOf = (items: Item[]): number =>
127	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
128	
129	const damagePayoutOf = (damage: Damage): number => damage.amount - DEDUCTIBLE;
130	
131	const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
132	  const policy = scenario.steps[claimStep.policy] as QuoteStep;
133	  const cap = insuranceSumOf(policy.items) * CAP_MULTIPLIER;
134	  const payout = claimStep.incident.damages.reduce(
135	    (sum, damage) => sum + damagePayoutOf(damage),
136	    0,
137	  );
138	  return { payout, remainingCap: cap - payout };
139	};
140	
141	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
142	  const results: StepResult[] = scenario.steps.map((step, index) => {
143	    if (step.op === "quote") {
144	      return {
145	        premium: quotePremium(step.items, scenario.customer, isFollowUpContract(index)),
146	      };
147	    }
148	    return processClaim(step, scenario);
149	  });
150	  return { results };
151	};
