const damagePayoutOf = (damage: Damage): number => damage.amount - DEDUCTIBLE;

const incidentPayoutOf = (incident: Incident): number =>
  incident.damages.reduce((sum, damage) => sum + damagePayoutOf(damage), 0);

const policyCapOf = (originatingQuote: QuoteStep): number =>
  insuranceSumOf(originatingQuote.items) * CAP_MULTIPLIER;

const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
  const originatingQuote = scenario.steps[claimStep.policy] as QuoteStep;
  const payout = incidentPayoutOf(claimStep.incident);
  return { payout, remainingCap: policyCapOf(originatingQuote) - payout };
};
